      "content": "// src/modules/comments/routes.js
const express = require('express');
const router = express.Router();
const commentsService = require('./service');
const { sendError } = require('../../lib/errors');

router.post('/', async (req, res) => {
  const { message } = req.body;
  if (!message || typeof message !== 'string') {
    return sendError(res, 400, 'INVALID_MESSAGE', 'Message must be a non-empty string.');
  }

  try {
    const comment = await commentsService.createComment(message);
    res.status(201).json({ comment });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'An internal error occurred.');
  }
});

router.get('/', async (req, res) => {
  try {
    const comments = await commentsService.getComments();
    res.json({ comments });
  } catch (error) {
    sendError(res, 500, 'INTERNAL_ERROR', 'An internal error occurred.');
  }
});

module.exports = router;
